#!/usr/bin/env python3
"""Mutation-scoring harness for editorMoveCursor.

Patches each mutant (by line number) onto the current kilo.c (which already
contains the editorMoveCursor contract), runs the canonical CBMC pipeline, and
classifies the mutant as KILLED (verification fails) or SURVIVED (succeeds).
editorMoveCursor has no callees, so no contract replacement is needed.
"""
import os, re, subprocess, sys, tempfile, shutil, concurrent.futures

KILO = "/app/kilo/kilo.c"
MUT = "/tmp/emc_mutants.txt"
F = "editorMoveCursor"
DEPTH = os.environ.get("DEPTH", "200")

def parse_mutants(path):
    text = open(path).read()
    blocks = text.split("--- original")
    muts = []
    for b in blocks[1:]:
        m = re.search(r'@@ -(\d+)', b)
        if not m:
            continue
        lineno = int(m.group(1))
        plus = None
        for ln in b.splitlines():
            if ln.startswith('+++'):
                continue
            if ln.startswith('+'):
                plus = ln[1:]
                break
        muts.append((lineno, plus, b.strip()))
    return muts

def build_source(lineno, mutline):
    lines = open(KILO).read().split('\n')
    if lineno is not None:
        lines[lineno-1] = mutline
    return '\n'.join(lines)

def run_cbmc(src, workdir):
    f = os.path.join(workdir, "m.c")
    open(f, 'w').write(src)
    g = os.path.join(workdir, "m.goto")
    c = os.path.join(workdir, "chk.goto")
    def sh(cmd):
        return subprocess.run(cmd, cwd=workdir, capture_output=True, text=True, timeout=120)
    r = sh(["goto-cc", "-o", g, f, "--function", F])
    if r.returncode != 0:
        return ("GOTOCC_ERR", r.stderr[-500:])
    sh(["goto-instrument", "--partial-loops", "--unwind", "5", g, g])
    sh(["goto-instrument", "--enforce-contract", F, g, c])
    try:
        r = subprocess.run(["cbmc", c, "--function", F, "--depth", DEPTH],
                           cwd=workdir, capture_output=True, text=True, timeout=300)
    except subprocess.TimeoutExpired:
        return ("TIMEOUT", "")
    out = r.stdout
    if "VERIFICATION SUCCESSFUL" in out:
        return ("SUCCESS", "")
    if "VERIFICATION FAILED" in out:
        fails = [l for l in out.splitlines() if ": FAILURE" in l]
        return ("FAILED", fails[:3])
    return ("OTHER", out[-500:])

def classify(args):
    lineno, mutline, diff = args
    d = tempfile.mkdtemp()
    try:
        src = build_source(lineno, mutline)
        verdict, info = run_cbmc(src, d)
    finally:
        shutil.rmtree(d, ignore_errors=True)
    return (lineno, mutline, verdict, info)

def main():
    muts = parse_mutants(MUT)
    d = tempfile.mkdtemp()
    base_v, base_i = run_cbmc(build_source(None, None), d)
    shutil.rmtree(d, ignore_errors=True)
    print(f"BASELINE (original): {base_v} {base_i if base_v!='SUCCESS' else ''}")
    if base_v != "SUCCESS":
        print("Baseline does not verify; aborting scoring.")
        return
    tasks = [(ln, ml, df) for (ln, ml, df) in muts]
    killed = survived = other = 0
    survivors = []
    with concurrent.futures.ThreadPoolExecutor(max_workers=8) as ex:
        for (lineno, mutline, verdict, info) in ex.map(classify, tasks):
            if verdict == "FAILED":
                killed += 1
                tag = "KILL"
            elif verdict == "SUCCESS":
                survived += 1
                survivors.append((lineno, mutline.strip()))
                tag = "SURV"
            else:
                other += 1
                survivors.append((lineno, mutline.strip() + f"  [{verdict}]"))
                tag = verdict
            print(f"  [{tag}] L{lineno}: {mutline.strip()[:80]}")
    print(f"\nKILLED={killed} SURVIVED={survived} OTHER={other} TOTAL={len(muts)}")
    print("Survivors:")
    for ln, ml in sorted(survivors):
        print(f"  L{ln}: {ml[:90]}")

if __name__ == "__main__":
    main()

